sp_angular_provider.script:
/* Use this Directive to show popover on GoJS graph tree
Usage in a widget's HTML:
	AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
		<dtech-graph-object-tooltip id="toolTipDIV"
			dtech-main-text="{{data.title}}"
    </dtech-graph-object-tooltip>

	//Of the 5 parameters, dtechCustomClass, dtechPlacement and dtechPrefixText are not required.

	//dtechCustomClass should be a string that is found as a CSS Selector (theme or widget); can be omitted from widget's HTML
	//dtechEndIndex can be a number or string 0-9,
	dtechMainText should be a string,
	//dtechPlacement should be a strings, see UI Bootstrap's web site for values, defaults to top if omitted from widget's HTML
	//dtechPrefixText should be a string; can be omitted from widget's HTML

	Here are two ways to get the HTML for the directive to use:
	1. template: htmlTemplate
		var htmlTemplate = '<div>some simple html goes here</div>' + '<div> as a contactenated string</div'
	2. templateUrl: getTemplateUrl('x_153465_discovert_dtechShowEllipsisWithTooltip.html')
	    In UI Macros, create a new macro, remove default XML code and carefully write the desired HTML, lacks syntax checking for HTML.

//
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
// Script Continued Below
// 2.8 | 2022-02-18 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
//										   
*/
function dtechGraphObjectTooltip(getTemplateUrl, spModal) {
	var jsController =
		function($scope) {
			console.log('start jsController');

			$scope.closePopover = function() {
				console.log('start closePopover()');

				var toolTipDIV = angular.element(document.getElementById('toolTipDIV'))[0];
				toolTipDIV.style.display = "none";
				toolTipDIV = undefined;
				console.log('end closePopover()');
			}

			$scope.openUserProfileModal = function() {
				console.log('sys_id' + $scope.dtechMainText.sys_id);
		spModal.open({
			title: 'User Profile',
			backdrop:'static',
			widget: 'tasker-user-profile',
			widgetInput: {
				//table: c.data.table,
				//view: 'Simple',
				sys_id: $scope.dtechMainText.sys_id,
				//omitHeader: 'true',
				isModal: true //,
			},
			size: 'lg',
			buttons: [],
			// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		});		
	};
			console.log('end jsController');
		};

	return {
		restrict: 'E',
		scope: {
			dtechMainText: '<' // @: string 1 way, =: object 2 way, <: object 1 way
		},
		controller: jsController,
		templateUrl: getTemplateUrl('x_153465_discovert_dtechGraphObjectTooltip.html')
	};
}
